<template lang="en">
<div class="my-popups">
    <loader :is-visible="isLoading"></loader>
    
        <div class="modal my-popups right fade d-block" :class="{ show: isShown }">
             <div role="document" class="modal-dialog" style="max-width: 1000px !important;">
            <div class="modal-content">
                <div class="modal-header theme-primary partition-full d-flex">
                    <h4 class="modal-title">{{ $t('AvailableContracts') }}</h4>
                    <button type="button" class="close" v-on:click="Close">
                        <em class="fa fa-times" aria-hidden="true"></em>
                    </button>
                </div>

                <div class="modal-body">
                    <section>
                        <tg-list :IsShowAction="false" ModuleName="Billing" SubModuleCode="Billing" :LegendArray="[]" :RenderRowActionMethod="renderActions" 
                        v-on:ActionButtonClick="actionButtonClick" :widgets="[]" IdentityColumn="ParentId" :listType="['List']" :ListData="AvailableContractData" 
                        :HeaderData="Headers" :HeaderButtons="listheaderbuttons" :TotalRecords="TotalRecords" :SearchFields="topSearchFields" :IsSearchFieldsOnTop="true" 
                        SearchPosition="top" :ListDataCallBackFunction="FetchData" :showCheckBox="true" :SortExp="SortExp" :SortBy="SortBy" :NorecordfoundText="$t('NoRecordfound')" 
                        :HeaderText="$t('AvailableContracts')" v-on:LeftsearchButtonClick="leftCommonSearch" v-on:PagerButtonClick="pagerMethod" v-on:HeaderButtonClick="commonHeaderButtonClick"
                         v-on:SortdataButtonClick="sortdata">
                            <template v-slot:slotdata="{ data }">
                                <template v-if="data.column.COLUMN_NAME == 'ParentName'">
                                    <span>
                                        <div class="text">
                                            <span :title="data.row.ParentName" class="">{{data.row.ParentName}}.</span>
                                        </div>
                                    </span>
                                </template>
                            </template>
                        </tg-list>
                        <dynamic-form lang="en" ref="AvailableContract" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit" :mandatorytext='MandatoryString'>
                        </dynamic-form>
                    </section>
                </div>
            </div>
        </div>
    </div>
</div>
</template>

<script>
import { create } from 'sortablejs';
import DataService from '../../services/DataService';

export default {
    data() {
        return {
            listheaderbuttons: [],
            listActions: [],
            isLoading: false,
            isShown: false,
            AvailableContractData: [],
            AssignBiller: [],
            SortBy: '',
            SortExp: '',
            PageSize: 10,
            PageNumber: 1,
            TotalRecords: 0,
            CurrentPage: 1,
            TotalPages: 0,
            noRecords: false,
            searchCondition: '',
            FormSchema: [],
            topSearchFields: [{
                fieldName: 'Search By Name',
                fieldType: "text",
                fieldSearchConditionName: [''],
                paramName: "ContractName",
                isSearch: true,
                value: "",
                listOptions: []
            }],
            Headers: [{
                "COLUMN_NAME": "ParentName",
                "DATA_TYPE": "text",
                "SORTABLE": true,
                "VISIBLE": true,
                "DISPLAY_NAME": 'Contract Name',
                "DISPLAY_ORDER": 1,
                settings: {
                    isInSlot: true
                }
            }, ],
            MandatoryString: 'Fields marked with an asterisk (*) are mandatory.',
            buttons: [{
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>Next",
                    isVisible: true
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Cancel",
                    onClick: this.Close
                }
            ]
        };
    },
     mounted() {
        this.$nextTick(() => {
            setTimeout(() => {                
                this.isShown = true;  
            }, 50);
        });
    },  
     created: async function (){
        await this.FetchData();
    },
    methods: {
        FetchData() {
            const vm = this;
            vm.isLoading = true;
            const url = `pageNum=${vm.PageNumber}&pageSize=${vm.PageSize}&reqFrom=MANAGEBILLER&search=${vm.searchCondition}&userId=&screenName=`;
            debugger;
            DataService.GetAvailableContracts(url).then((response) => {
                try {
                    if (response?.data?.result) {
                        vm.AvailableContractData = JSON.parse(response?.data?.result || "null");
                        // vm.TotalRecords = vm.AvailableContractData[0].TOTAL_RECORDS;
                        // vm.TotalPages = Math.ceil(vm.TotalRecords / vm.PageSize);
                        // vm.CurrentPage = vm.PageNumber;                   
                        // vm.noRecords = false;
                        vm.isLoading = false;
                    } else {
                        vm.AvailableContractData = [];
                        vm.noRecords = true;
                        vm.TotalRecords = 0
                        vm.isLoading = false;
                    }
                } catch (e) {
                    console.error("Error parsing contract result:", e);
                }
            })

        },
        leftCommonSearch: function (value) {
            this.PageNumber = value.PageNumber;
            this.isPaged = 1;

            if (typeof value.searchConditionJson !== 'undefined') {
                this.searchCondition = value.searchConditionJson.split('=')[1] || '';
            } else {
                this.searchCondition = "";
            }
            this.FetchData();
        },
        commonHeaderButtonClick: function (event) {
            switch (event.callbackfunction) {

            }
        },

        onSubmit(formfields) {
            debugger;
            var vm = this;
            var val = "";
            vm.isLoading = true;
            $('.chkItems:checkbox:checked').not("[id^='chkAll_0']").each(function () {
                if (val.length > 0)
                    val += ',';
                val += $(this).val();
            });
            if (val != null) {
                const ids = val.toString().split(',').map(Number);
                vm.AssignBiller = vm.AvailableContractData.filter(item => ids.includes(item.ParentId));
                const payload = {
                    formfields: formfields,
                    AssignBiller: vm.AssignBiller
                };
                vm.$emit('submit-data', payload);
                vm.$parent.isAddContract = false;

            } else {
                vm.ShowAlert(vm.$t("Selectanyrecordtodelete"));
            }

        },

        Close() {
            this.$parent.isAddContract = false;
        },
        sortdata: function (sortBy) {
            this.SortBy = sortBy;
            var sortExp = 'ASC';
            if (this.SortExp == 'ASC') {
                sortExp = 'DESC';
            }
            this.SortExp = sortExp;
            this.SortBy = sortBy;
            this.SortExp = sortExp;
            this.PageNumber = 1;
            this.FetchData();
        },
        pagerMethod: function (value) {
            this.PageSize = value.PageSize;
            this.PageNumber = value.PageNumber;
            this.FetchData();
        },
        renderActions: function (row) {
            var self = this;
            let rtnActionArray = [];
            // self.listActions.forEach(actionItem => {
            //     let action = {
            //         ...actionItem
            //     };
            //     switch (action.title) {

            //     }
            //     rtnActionArray.push(action);
            // });
            return rtnActionArray;
        },
        actionButtonClick: function (callbackfunction, item) {
            switch (callbackfunction) {

            }
        },
    }
};
</script>
